import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import NFTDevelopmentScreen from "@screens/nft-development-company";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const NFTDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "NFT Marketplace Development Company", link: null },
  ];
  const { data } = props;
  const fileUrl =
    data?.nftMarketPlaceImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Custom NFT marketplace development by Justtry Technologies, enabling businesses to launch secure platforms for minting, trading, and managing digital assets.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },
      {
        "@type": "Product",
        name: validData?.title || "NFT Marketplace Development",
        description:
          "Justtry Technologies is a top NFT Marketplace Development Company, creating bespoke platforms that empower seamless and secure asset trading and enhanced user experiences.",
        url: "https://justtrytech.com/nft-marketplace-development-company/",
        brand: {
          "@type": "Brand",
          name: "Justtry Technologies",
          logo: "https://justtrytech.com/static/410c801e805fa7015baa3458ddd8c7b5/c456f/nft-development.png",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.5,
          reviewCount: 450,
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How much does NFT marketplace development cost?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Typically ranges from $40,000 to $120,000+, depending on features, blockchain, and security needs.",
            },
          },
          {
            "@type": "Question",
            name: "How to choose a reliable NFT marketplace development company?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Choose a reliable NFT marketplace development company by reviewing portfolio, client feedback, security practices, blockchain expertise, customization options, and post-launch support.",
            },
          },
          {
            "@type": "Question",
            name: "Best platforms for building an NFT marketplace?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Top platforms for building an NFT marketplace include Ethereum, Polygon, Solana, and BNB Chain, offering strong security, scalability, lower fees, and broad ecosystem support.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <NFTDevelopmentScreen db={db} />
    </Layout_v2>
  );
};

export default NFTDevelopmentCompany;

export const queryData = graphql`
  query MyQuery {
    nftMarketPlaceImg: file(relativePath: { eq: "nft-marketplace.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allImageSharp {
      edges {
        node {
          gatsbyImageData
          id
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "nft-marketplace-development-company" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
